import { useCallback, useEffect, useState } from 'react';
import type { CleanupSite } from '../types';
import { SEED_SITES } from '../seed';

const STORAGE_KEY = 'cleansweep.sites.v1';

function loadSites(): CleanupSite[] {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return SEED_SITES;
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) return SEED_SITES;
    return parsed as CleanupSite[];
  } catch {
    return SEED_SITES;
  }
}

export function useCleanupSites() {
  const [sites, setSites] = useState<CleanupSite[]>(loadSites);

  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(sites));
    } catch {
      // storage unavailable (private mode, quota) — keep state in memory
    }
  }, [sites]);

  const addSite = useCallback((site: Omit<CleanupSite, 'id' | 'createdAt'>) => {
    const newSite: CleanupSite = {
      ...site,
      id: `site-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
      createdAt: Date.now(),
    };
    setSites((prev) => [newSite, ...prev]);
    return newSite;
  }, []);

  const updateSite = useCallback((id: string, patch: Partial<CleanupSite>) => {
    setSites((prev) =>
      prev.map((s) => (s.id === id ? { ...s, ...patch, id: s.id } : s)),
    );
  }, []);

  const deleteSite = useCallback((id: string) => {
    setSites((prev) => prev.filter((s) => s.id !== id));
  }, []);

  const joinSite = useCallback((id: string) => {
    setSites((prev) =>
      prev.map((s) =>
        s.id === id ? { ...s, volunteersJoined: s.volunteersJoined + 1 } : s,
      ),
    );
  }, []);

  return { sites, addSite, updateSite, deleteSite, joinSite };
}

