import { useEffect } from 'react';
import { MapContainer, Marker, TileLayer, useMap, useMapEvents } from 'react-leaflet';
import L from 'leaflet';
import type { CleanupSite, SiteStatus } from '../types';

const STATUS_COLORS: Record<SiteStatus, string> = {
  planned: '#2563eb',
  active: '#16a34a',
  completed: '#64748b',
};

function makeIcon(status: SiteStatus, selected: boolean) {
  const color = STATUS_COLORS[status];
  const size = selected ? 34 : 26;
  const ring = selected
    ? `<circle cx="17" cy="17" r="15.5" fill="none" stroke="${color}" stroke-width="2" opacity="0.45"/>`
    : '';
  return L.divIcon({
    className: 'cleanup-marker',
    iconSize: [size, size + 6],
    iconAnchor: [size / 2, size + 4],
    html: `
      <svg width="${size}" height="${size + 6}" viewBox="0 0 34 40" xmlns="http://www.w3.org/2000/svg">
        ${ring}
        <path d="M17 2C10.4 2 5 7.4 5 14c0 8.4 10.3 19.6 11.4 20.7a1.4 1.4 0 0 0 2.1 0C19.7 33.6 30 22.4 30 14 30 7.4 24.6 2 17 2z" fill="${color}" stroke="#ffffff" stroke-width="2"/>
        <circle cx="17" cy="14" r="4.5" fill="#ffffff"/>
      </svg>`,
  });
}

function ClickHandler({ onMapClick }: { onMapClick?: (lat: number, lng: number) => void }) {
  useMapEvents({
    click(e) {
      onMapClick?.(e.latlng.lat, e.latlng.lng);
    },
  });
  return null;
}

function FlyTo({ target }: { target: { lat: number; lng: number; zoom?: number } | null }) {
  const map = useMap();
  useEffect(() => {
    if (target) {
      map.flyTo([target.lat, target.lng], target.zoom ?? 15, { duration: 0.8 });
    }
  }, [target, map]);
  return null;
}

interface CleanupMapProps {
  sites: CleanupSite[];
  selectedId: string | null;
  onSelect: (id: string) => void;
  onMapClick?: (lat: number, lng: number) => void;
  draftPin: { lat: number; lng: number } | null;
  flyTo: { lat: number; lng: number; zoom?: number } | null;
}

export default function CleanupMap({
  sites,
  selectedId,
  onSelect,
  onMapClick,
  draftPin,
  flyTo,
}: CleanupMapProps) {
  return (
    <MapContainer
      center={[37.7577, -122.4376]}
      zoom={12}
      className="map"
      scrollWheelZoom
    >
      <TileLayer
        attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors &copy; <a href="https://carto.com/attributions">CARTO</a>'
        url="https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png"
      />
      <ClickHandler onMapClick={onMapClick} />
      <FlyTo target={flyTo} />
      {sites.map((site) => (
        <Marker
          key={site.id}
          position={[site.lat, site.lng]}
          icon={makeIcon(site.status, site.id === selectedId)}
          eventHandlers={{ click: () => onSelect(site.id) }}
        />
      ))}
      {draftPin && (
        <Marker
          position={[draftPin.lat, draftPin.lng]}
          icon={L.divIcon({
            className: 'cleanup-marker draft',
            iconSize: [30, 36],
            iconAnchor: [15, 34],
            html: `
              <svg width="30" height="36" viewBox="0 0 34 40" xmlns="http://www.w3.org/2000/svg">
                <path d="M17 2C10.4 2 5 7.4 5 14c0 8.4 10.3 19.6 11.4 20.7a1.4 1.4 0 0 0 2.1 0C19.7 33.6 30 22.4 30 14 30 7.4 24.6 2 17 2z" fill="#f59e0b" stroke="#ffffff" stroke-width="2" stroke-dasharray="4 2"/>
                <circle cx="17" cy="14" r="4.5" fill="#ffffff"/>
              </svg>`,
          })}
        />
      )}
    </MapContainer>
  );
}

