import type { CleanupSite, SiteStatus, WasteType } from '../types';
import { ALL_WASTE_TYPES, STATUS_LABELS } from '../types';

export interface Filters {
  statuses: Set<SiteStatus>;
  wasteTypes: Set<WasteType>;
  search: string;
}

interface SidebarProps {
  sites: CleanupSite[];
  allSites: CleanupSite[];
  filters: Filters;
  onFiltersChange: (filters: Filters) => void;
  selectedId: string | null;
  onSelect: (id: string) => void;
  onAddClick: () => void;
  addingSite: boolean;
}

function formatDate(iso: string) {
  const d = new Date(`${iso}T12:00:00`);
  return d.toLocaleDateString(undefined, {
    weekday: 'short',
    month: 'short',
    day: 'numeric',
  });
}

export default function Sidebar({
  sites,
  allSites,
  filters,
  onFiltersChange,
  selectedId,
  onSelect,
  onAddClick,
  addingSite,
}: SidebarProps) {
  const toggleStatus = (status: SiteStatus) => {
    const next = new Set(filters.statuses);
    if (next.has(status)) next.delete(status);
    else next.add(status);
    onFiltersChange({ ...filters, statuses: next });
  };

  const toggleWaste = (waste: WasteType) => {
    const next = new Set(filters.wasteTypes);
    if (next.has(waste)) next.delete(waste);
    else next.add(waste);
    onFiltersChange({ ...filters, wasteTypes: next });
  };

  const counts = {
    planned: allSites.filter((s) => s.status === 'planned').length,
    active: allSites.filter((s) => s.status === 'active').length,
    completed: allSites.filter((s) => s.status === 'completed').length,
    volunteers: allSites.reduce((sum, s) => sum + s.volunteersJoined, 0),
  };

  return (
    <aside className="sidebar">
      <header className="brand">
        <div className="brand-mark" aria-hidden>
          🧹
        </div>
        <div>
          <h1>CleanSweep</h1>
          <p>Community cleanup tracker</p>
        </div>
      </header>

      <div className="stats">
        <div className="stat">
          <span className="stat-value">{counts.active}</span>
          <span className="stat-label">Active</span>
        </div>
        <div className="stat">
          <span className="stat-value">{counts.planned}</span>
          <span className="stat-label">Planned</span>
        </div>
        <div className="stat">
          <span className="stat-value">{counts.completed}</span>
          <span className="stat-label">Done</span>
        </div>
        <div className="stat">
          <span className="stat-value">{counts.volunteers}</span>
          <span className="stat-label">Volunteers</span>
        </div>
      </div>

      <input
        className="search"
        type="search"
        placeholder="Search sites or organizers…"
        value={filters.search}
        onChange={(e) => onFiltersChange({ ...filters, search: e.target.value })}
      />

      <div className="filter-group">
        <span className="filter-title">Status</span>
        <div className="chip-row">
          {(Object.keys(STATUS_LABELS) as SiteStatus[]).map((status) => (
            <button
              key={status}
              className={`chip chip-${status} ${filters.statuses.has(status) ? 'on' : ''}`}
              onClick={() => toggleStatus(status)}
              aria-pressed={filters.statuses.has(status)}
            >
              {STATUS_LABELS[status]}
            </button>
          ))}
        </div>
      </div>

      <div className="filter-group">
        <span className="filter-title">Waste type</span>
        <div className="chip-row">
          {ALL_WASTE_TYPES.map((waste) => (
            <button
              key={waste}
              className={`chip chip-waste ${filters.wasteTypes.has(waste) ? 'on' : ''}`}
              onClick={() => toggleWaste(waste)}
              aria-pressed={filters.wasteTypes.has(waste)}
            >
              {waste}
            </button>
          ))}
        </div>
      </div>

      <button
        className={`add-button ${addingSite ? 'cancel' : ''}`}
        onClick={onAddClick}
      >
        {addingSite ? '✕ Cancel — stop placing pin' : '＋ Add a cleanup site'}
      </button>
      {addingSite && (
        <p className="add-hint">Click anywhere on the map to drop a pin for the new site.</p>
      )}

      <div className="site-count">
        {sites.length} of {allSites.length} sites shown
      </div>

      <ul className="site-list">
        {sites.map((site) => {
          const pct = Math.min(
            100,
            Math.round((site.volunteersJoined / Math.max(1, site.volunteersNeeded)) * 100),
          );
          return (
            <li key={site.id}>
              <button
                className={`site-card ${site.id === selectedId ? 'selected' : ''}`}
                onClick={() => onSelect(site.id)}
              >
                <div className="site-card-top">
                  <span className={`status-dot dot-${site.status}`} />
                  <span className="site-name">{site.name}</span>
                </div>
                <div className="site-meta">
                  <span>{STATUS_LABELS[site.status]}</span>
                  <span aria-hidden>·</span>
                  <span>{formatDate(site.date)}</span>
                </div>
                <div className="volunteer-bar" title={`${site.volunteersJoined} of ${site.volunteersNeeded} volunteers`}>
                  <div className="volunteer-fill" style={{ width: `${pct}%` }} />
                </div>
                <div className="volunteer-text">
                  {site.volunteersJoined}/{site.volunteersNeeded} volunteers
                </div>
              </button>
            </li>
          );
        })}
        {sites.length === 0 && (
          <li className="empty-state">No sites match your filters.</li>
        )}
      </ul>
    </aside>
  );
}

