import { useMemo, useState } from 'react';
import 'leaflet/dist/leaflet.css';
import CleanupMap from './components/CleanupMap';
import Sidebar, { type Filters } from './components/Sidebar';
import SiteDetail from './components/SiteDetail';
import SiteForm, { type SiteFormValues } from './components/SiteForm';
import { useCleanupSites } from './hooks/useCleanupSites';
import type { CleanupSite } from './types';
import './app.css';

export default function App() {
  const { sites, addSite, updateSite, deleteSite, joinSite } = useCleanupSites();
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [addingSite, setAddingSite] = useState(false);
  const [draftPin, setDraftPin] = useState<{ lat: number; lng: number } | null>(null);
  const [formOpen, setFormOpen] = useState(false);
  const [editingSite, setEditingSite] = useState<CleanupSite | null>(null);
  const [flyTo, setFlyTo] = useState<{ lat: number; lng: number; zoom?: number } | null>(null);
  const [filters, setFilters] = useState<Filters>({
    statuses: new Set(),
    wasteTypes: new Set(),
    search: '',
  });

  const filteredSites = useMemo(() => {
    const q = filters.search.trim().toLowerCase();
    return sites.filter((site) => {
      if (filters.statuses.size > 0 && !filters.statuses.has(site.status)) return false;
      if (
        filters.wasteTypes.size > 0 &&
        !site.wasteTypes.some((w) => filters.wasteTypes.has(w))
      )
        return false;
      if (
        q &&
        !site.name.toLowerCase().includes(q) &&
        !site.organizer.toLowerCase().includes(q) &&
        !site.description.toLowerCase().includes(q)
      )
        return false;
      return true;
    });
  }, [sites, filters]);

  const selectedSite = sites.find((s) => s.id === selectedId) ?? null;

  const handleSelect = (id: string) => {
    setSelectedId(id);
    const site = sites.find((s) => s.id === id);
    if (site) setFlyTo({ lat: site.lat, lng: site.lng });
  };

  const handleMapClick = (lat: number, lng: number) => {
    if (!addingSite && !formOpen) return;
    setDraftPin({ lat, lng });
    if (addingSite && !formOpen) setFormOpen(true);
  };

  const handleFormSubmit = (values: SiteFormValues) => {
    if (editingSite) {
      updateSite(editingSite.id, values);
      setSelectedId(editingSite.id);
    } else {
      const created = addSite(values);
      setSelectedId(created.id);
      setFlyTo({ lat: created.lat, lng: created.lng });
    }
    closeForm();
  };

  const closeForm = () => {
    setFormOpen(false);
    setEditingSite(null);
    setDraftPin(null);
    setAddingSite(false);
  };

  return (
    <div className="app">
      <Sidebar
        sites={filteredSites}
        allSites={sites}
        filters={filters}
        onFiltersChange={setFilters}
        selectedId={selectedId}
        onSelect={handleSelect}
        addingSite={addingSite}
        onAddClick={() => {
          setAddingSite((v) => !v);
          setDraftPin(null);
        }}
      />
      <main className="map-area">
        <CleanupMap
          sites={filteredSites}
          selectedId={selectedId}
          onSelect={handleSelect}
          onMapClick={handleMapClick}
          draftPin={draftPin}
          flyTo={flyTo}
        />
        {selectedSite && !formOpen && (
          <SiteDetail
            site={selectedSite}
            onClose={() => setSelectedId(null)}
            onEdit={(site) => {
              setEditingSite(site);
              setFormOpen(true);
            }}
            onDelete={(id) => {
              deleteSite(id);
              setSelectedId(null);
            }}
            onJoin={joinSite}
            onStatusChange={(id, status) => updateSite(id, { status })}
          />
        )}
      </main>
      {formOpen && (
        <SiteForm
          initial={editingSite ?? undefined}
          draftLocation={draftPin}
          onSubmit={handleFormSubmit}
          onCancel={closeForm}
        />
      )}
    </div>
  );
}
TSXEOF"}

