html,
body,
#root {
  height: 100%;
  margin: 0;
}

body {
  color: var(--ink);
  background: var(--bg);
}

.app {
  display: flex;
  height: 100%;
  overflow: hidden;
}

/* ---------- Sidebar ---------- */

.sidebar {
  width: 380px;
  min-width: 380px;
  height: 100%;
  overflow-y: auto;
  background: var(--card);
  border-right: 1px solid var(--border);
  padding: 20px;
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.brand {
  display: flex;
  align-items: center;
  gap: 12px;
}

.brand-mark {
  font-size: 26px;
  background: var(--green-soft);
  border-radius: 12px;
  width: 48px;
  height: 48px;
  display: grid;
  place-items: center;
}

.brand h1 {
  font-size: 20px;
  margin: 0;
  letter-spacing: -0.02em;
}

.brand p {
  margin: 0;
  font-size: 13px;
  color: var(--ink-muted);
}

.stats {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 8px;
}

.stat {
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 10px 6px;
  text-align: center;
}

.stat-value {
  display: block;
  font-size: 20px;
  font-weight: 700;
}

.stat-label {
  font-size: 11px;
