  border-radius: 10px;
  font-size: 14px;
}

.search:focus {
  outline: 2px solid var(--green);
  outline-offset: -1px;
  border-color: transparent;
}

.filter-group {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.filter-title {
  font-size: 12px;
  font-weight: 600;
  text-transform: uppercase;
