}

.chip.on.chip-active {
  background: var(--green-soft);
  border-color: var(--green);
  color: var(--green);
}

.chip.on.chip-completed {
  background: var(--slate-soft);
  border-color: var(--slate);
  color: var(--slate);
}

.chip.on.chip-waste {
