.dot-planned {
  background: var(--blue);
}

.dot-active {
  background: var(--green);
}

.dot-completed {
  background: var(--slate);
}

.site-name {
  font-weight: 600;
  font-size: 14px;
}

.site-meta {
  font-size: 12px;
  color: var(--ink-muted);
  display: flex;
  gap: 6px;
}

.volunteer-bar {
  height: 6px;
  border-radius: 999px;
  background: var(--slate-soft);
  overflow: hidden;
}

.volunteer-bar.large {
  height: 10px;
}

.volunteer-fill {
  height: 100%;
  background: var(--green);
  border-radius: 999px;
  transition: width 0.3s ease;
}

.volunteer-text {
  font-size: 12px;
  color: var(--ink-muted);
}

.empty-state {
  text-align: center;
  color: var(--ink-muted);
  font-size: 14px;
  padding: 24px 0;
