}

.primary-button:hover {
  background: #15803d;
}

.secondary-button {
  padding: 9px 16px;
  border: 1px solid var(--border);
  border-radius: 10px;
  background: var(--card);
  font-size: 14px;
  cursor: pointer;
  color: var(--ink);
}

.secondary-button:hover {
  border-color: var(--slate);
}

.danger-button {
