  gap: 8px;
  margin-top: 4px;
}

.form-actions .primary-button {
  width: auto;
  padding: 10px 22px;
}

/* ---------- Responsive ---------- */

@media (max-width: 860px) {
  .app {
    flex-direction: column;
  }

  .sidebar {
    width: 100%;
    min-width: 0;
    height: 46%;
    border-right: none;
