Region containment helper: haversine-ish simple: distance in meters via equirectangular approx:
```ts
function distanceMeters(lat1,lng1,lat2,lng2) {
  const R=6371000; const toRad=(d:number)=>d*Math.PI/180;
  const dLat=toRad(lat2-lat1), dLng=toRad(lng2-lng1);
  const a=Math.sin(dLat/2)**2 + Math.cos(toRad(lat1))*Math.cos(toRad(lat2))*Math.sin(dLng/2)**2;
  return 2*R*Math.asin(Math.sqrt(a));
}
export function findRegion(regions, lat, lng) { containing sorted by radius asc → first }
```
