import { useCallback, useEffect, useState } from 'react';
import type {
  CleanupSite,
  Region,
  SitePhoto,
  SitePin,
  SiteReport,
  SiteStatus,
  StatusEvent,
  VolunteerAssignment,
} from '../types';
import { uid } from '../types';
import { SEED_PINS, SEED_REGIONS, SEED_SITES } from '../seed';

const STORAGE_KEY = 'cleansweep.data.v2';

interface StoreShape {
  sites: CleanupSite[];
  regions: Region[];
  pins: SitePin[];
}

function defaultStore(): StoreShape {
  return { sites: SEED_SITES, regions: SEED_REGIONS, pins: SEED_PINS };
}

/* Migrate the v1 shape (array of sites with volunteersJoined: number). */
function migrateV1(rawSites: unknown[]): CleanupSite[] {
  return (rawSites as Record<string, unknown>[]).map((raw) => {
    const joined = typeof raw.volunteersJoined === 'number' ? raw.volunteersJoined : 0;
    const status = (raw.status as SiteStatus) ?? 'planned';
    const createdAt = typeof raw.createdAt === 'number' ? raw.createdAt : Date.now();
    return {
      id: String(raw.id ?? uid('site')),
      name: String(raw.name ?? 'Untitled site'),
      description: String(raw.description ?? ''),
      lat: Number(raw.lat) || 0,
      lng: Number(raw.lng) || 0,
      regionId: null,
      status,
      date: String(raw.date ?? new Date().toISOString().slice(0, 10)),
      wasteTypes: (raw.wasteTypes as CleanupSite['wasteTypes']) ?? ['general litter'],
      volunteersNeeded: Number(raw.volunteersNeeded) || 10,
      organizer: String(raw.organizer ?? 'Community member'),
      assignments: Array.from({ length: joined }, (_, i) => ({
        id: `vol-migrated-${raw.id}-${i}`,
        name: `Volunteer ${i + 1}`,
        role: 'Picker',
        assignedAt: createdAt,
      })),
      reports: [],
      photos: [],
      statusHistory: [{ id: uid('evt'), status, at: createdAt }],
      createdAt,
    };
  });
}

function loadStore(): StoreShape {
  try {
    const rawV2 = localStorage.getItem(STORAGE_KEY);
    if (rawV2) {
      const parsed = JSON.parse(rawV2) as Partial<StoreShape>;
      if (Array.isArray(parsed.sites) && Array.isArray(parsed.regions)) {
        return {
          sites: parsed.sites,
          regions: parsed.regions,
          pins: Array.isArray(parsed.pins) ? parsed.pins : [],
        };
      }
    }
    const rawV1 = localStorage.getItem('cleansweep.sites.v1');
    if (rawV1) {
      const parsed = JSON.parse(rawV1);
      if (Array.isArray(parsed)) {
        return { ...defaultStore(), sites: migrateV1(parsed) };
      }
    }
    return defaultStore();
  } catch {
    return defaultStore();
  }
}

function patchSite(
  sites: CleanupSite[],
  id: string,
  fn: (site: CleanupSite) => CleanupSite,
): CleanupSite[] {
  return sites.map((s) => (s.id === id ? fn(s) : s));
}

export function useCleanupSites() {
  const [store, setStore] = useState<StoreShape>(loadStore);
  const { sites, regions, pins } = store;

  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(store));
    } catch {
      // storage unavailable or quota exceeded (large photos) — keep in memory
    }
  }, [store]);

  /* ---------- Sites ---------- */

  const addSite = useCallback(
    (site: Omit<CleanupSite, 'id' | 'createdAt' | 'statusHistory'>) => {
      const now = Date.now();
      const newSite: CleanupSite = {
        ...site,
        id: uid('site'),
        createdAt: now,
        statusHistory: [{ id: uid('evt'), status: site.status, at: now }],
      };
      setStore((prev) => ({ ...prev, sites: [newSite, ...prev.sites] }));
      return newSite;
    },
    [],
  );

  const updateSite = useCallback(
    (id: string, patch: Partial<Omit<CleanupSite, 'id'>>) => {
      setStore((prev) => ({
        ...prev,
        sites: patchSite(prev.sites, id, (s) => {
          const next = { ...s, ...patch, id: s.id };
          if (patch.status && patch.status !== s.status) {
            next.statusHistory = [
              ...s.statusHistory,
              { id: uid('evt'), status: patch.status, at: Date.now() },
            ];
          }
          return next;
        }),
      }));
    },
    [],
  );

  const deleteSite = useCallback((id: string) => {
    setStore((prev) => ({ ...prev, sites: prev.sites.filter((s) => s.id !== id) }));
  }, []);

  const setSiteStatus = useCallback((id: string, status: SiteStatus, note?: string) => {
    setStore((prev) => ({
      ...prev,
      sites: patchSite(prev.sites, id, (s) => {
        if (s.status === status) return s;
        return {
          ...s,
          status,
          statusHistory: [
            ...s.statusHistory,
            { id: uid('evt'), status, at: Date.now(), note: note?.trim() || undefined },
          ],
        };
      }),
    }));
  }, []);

  /* ---------- Volunteers ---------- */

  const addAssignment = useCallback(
    (siteId: string, assignment: { name: string; role: string }) => {
      const entry: VolunteerAssignment = {
        id: uid('vol'),
        name: assignment.name.trim(),
        role: assignment.role,
        assignedAt: Date.now(),
      };
      setStore((prev) => ({
        ...prev,
        sites: patchSite(prev.sites, siteId, (s) => ({
          ...s,
          assignments: [...s.assignments, entry],
        })),
      }));
    },
    [],
  );

  const removeAssignment = useCallback((siteId: string, assignmentId: string) => {
    setStore((prev) => ({
      ...prev,
      sites: patchSite(prev.sites, siteId, (s) => ({
        ...s,
        assignments: s.assignments.filter((a) => a.id !== assignmentId),
      })),
    }));
  }, []);

  /* ---------- Reports ---------- */

  const addReport = useCallback(
    (siteId: string, report: { author: string; text: string; bagsCollected?: number }) => {
      const entry: SiteReport = {
        id: uid('rep'),
        at: Date.now(),
        author: report.author.trim() || 'Anonymous',
        text: report.text.trim(),
        bagsCollected: report.bagsCollected,
      };
      setStore((prev) => ({
        ...prev,
        sites: patchSite(prev.sites, siteId, (s) => ({
          ...s,
          reports: [entry, ...s.reports],
        })),
      }));
    },
    [],
  );

  const deleteReport = useCallback((siteId: string, reportId: string) => {
    setStore((prev) => ({
      ...prev,
      sites: patchSite(prev.sites, siteId, (s) => ({
        ...s,
        reports: s.reports.filter((r) => r.id !== reportId),
      })),
    }));
  }, []);

  /* ---------- Photos ---------- */

  const addPhoto = useCallback(
    (siteId: string, photo: { dataUrl: string; caption: string }) => {
      const entry: SitePhoto = {
        id: uid('photo'),
        dataUrl: photo.dataUrl,
        caption: photo.caption.trim(),
        at: Date.now(),
      };
      setStore((prev) => ({
        ...prev,
        sites: patchSite(prev.sites, siteId, (s) => ({
          ...s,
          photos: [entry, ...s.photos],
        })),
      }));
    },
    [],
  );

  const deletePhoto = useCallback((siteId: string, photoId: string) => {
    setStore((prev) => ({
      ...prev,
      sites: patchSite(prev.sites, siteId, (s) => ({
        ...s,
        photos: s.photos.filter((p) => p.id !== photoId),
      })),
    }));
  }, []);

  /* ---------- Regions ---------- */

  const addRegion = useCallback(
    (region: Omit<Region, 'id' | 'createdAt'>) => {
      const entry: Region = { ...region, id: uid('region'), createdAt: Date.now() };
      setStore((prev) => ({ ...prev, regions: [...prev.regions, entry] }));
      return entry;
    },
    [],
  );

  const deleteRegion = useCallback((id: string) => {
    setStore((prev) => ({
      ...prev,
      regions: prev.regions.filter((r) => r.id !== id),
      sites: prev.sites.map((s) => (s.regionId === id ? { ...s, regionId: null } : s)),
    }));
  }, []);

  /* ---------- Pins ---------- */

  const addPin = useCallback((pin: Omit<SitePin, 'id' | 'createdAt'>) => {
    const entry: SitePin = { ...pin, id: uid('pin'), createdAt: Date.now() };
    setStore((prev) => ({ ...prev, pins: [...prev.pins, entry] }));
    return entry;
  }, []);

  const deletePin = useCallback((id: string) => {
    setStore((prev) => ({ ...prev, pins: prev.pins.filter((p) => p.id !== id) }));
  }, []);

  return {
    sites,
    regions,
    pins,
    addSite,
    updateSite,
    deleteSite,
    setSiteStatus,
    addAssignment,
    removeAssignment,
    addReport,
    deleteReport,
    addPhoto,
    deletePhoto,
    addRegion,
    deleteRegion,
    addPin,
    deletePin,
  };
}

export type { StatusEvent };
