  });
}

function makePinIcon() {
  return L.divIcon({
    className: 'cleanup-marker',
    iconSize: [20, 20],
    iconAnchor: [10, 10],
    html: `
      <svg width="20" height="20" viewBox="0 0 20 20" xmlns="http://www.w3.org/2000/svg">
        <rect x="4" y="4" width="12" height="12" rx="2.5" transform="rotate(45 10 10)" fill="#f59e0b" stroke="#ffffff" stroke-width="2"/>
      </svg>`,
  });
}

function makeDraftIcon(mode: Exclude<PlacementMode, null>) {
  const color = mode === 'region' ? '#7c3aed' : mode === 'pin' ? '#f59e0b' : '#2563eb';
  if (mode === 'pin') return makePinIcon();
  return L.divIcon({
    className: 'cleanup-marker draft',
    iconSize: [30, 36],
    iconAnchor: [15, 34],
    html: `
      <svg width="30" height="36" viewBox="0 0 34 40" xmlns="http://www.w3.org/2000/svg">
        <path d="M17 2C10.4 2 5 7.4 5 14c0 8.4 10.3 19.6 11.4 20.7a1.4 1.4 0 0 0 2.1 0C19.7 33.6 30 22.4 30 14 30 7.4 24.6 2 17 2z" fill="${color}" stroke="#ffffff" stroke-width="2" stroke-dasharray="4 2"/>
        <circle cx="17" cy="14" r="4.5" fill="#ffffff"/>
      </svg>`,
  });
}

function ClickHandler({
  placementMode,
  onMapClick,
}: {
  placementMode: PlacementMode;
  onMapClick: (lat: number, lng: number) => void;
}) {
  useMapEvents({
    click(e) {
      if (placementMode) onMapClick(e.latlng.lat, e.latlng.lng);
    },
  });
  return null;
}

function CursorStyle({ placementMode }: { placementMode: PlacementMode }) {
  const map = useMap();
  useEffect(() => {
    const el = map.getContainer();
    el.style.cursor = placementMode ? 'crosshair' : '';
    return () => {
      el.style.cursor = '';
    };
  }, [map, placementMode]);
  return null;
}

function FlyTo({ target }: { target: { lat: number; lng: number; zoom?: number } | null }) {
  const map = useMap();
  useEffect(() => {
    if (target) {
      map.flyTo([target.lat, target.lng], target.zoom ?? 15, { duration: 0.8 });
    }
  }, [target, map]);
  return null;
}

interface CleanupMapProps {
