        url="https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png"
      />
      <ClickHandler placementMode={placementMode} onMapClick={onMapClick} />
      <CursorStyle placementMode={placementMode} />
      <FlyTo target={flyTo} />

      {regions.map((region) => (
        <Circle
          key={region.id}
          center={[region.center.lat, region.center.lng]}
          radius={region.radiusMeters}
          pathOptions={{
            color: region.color,
