              {pin.note && <p>{pin.note}</p>}
              <button onClick={() => onDeletePin(pin.id)}>Remove pin</button>
            </div>
          </Popup>
        </Marker>
      ))}

      {sites.map((site) => (
        <Marker
          key={site.id}
          position={[site.lat, site.lng]}
          icon={makeSiteIcon(site.status, site.id === selectedId)}
          eventHandlers={{ click: () => onSelectSite(site.id) }}
        />
      ))}

      {draftPin && placementMode && placementMode !== 'region' && (
        <Marker position={[draftPin.lat, draftPin.lng]} icon={makeDraftIcon(placementMode)} />
      )}
      {draftPin && placementMode === 'region' && (
        <Marker position={[draftPin.lat, draftPin.lng]} icon={makeDraftIcon('region')} />
      )}
    </MapContainer>
  );
}
