import { useState } from 'react';
import type { CleanupSite, SitePhoto, SiteStatus } from '../types';
import { STATUS_LABELS, VOLUNTEER_ROLES, volunteersJoined } from '../types';

type Tab = 'overview' | 'volunteers' | 'reports' | 'photos' | 'history';

interface SiteDetailProps {
  site: CleanupSite;
  regionName: string | null;
  onClose: () => void;
  onEdit: (site: CleanupSite) => void;
  onDelete: (id: string) => void;
  onStatusChange: (id: string, status: SiteStatus, note?: string) => void;
  onAddAssignment: (siteId: string, a: { name: string; role: string }) => void;
  onRemoveAssignment: (siteId: string, assignmentId: string) => void;
  onAddReport: (
    siteId: string,
    r: { author: string; text: string; bagsCollected?: number },
  ) => void;
  onDeleteReport: (siteId: string, reportId: string) => void;
  onPhotoUpload: (siteId: string, file: File, caption: string) => void;
  onDeletePhoto: (siteId: string, photoId: string) => void;
  onPhotoClick: (photo: SitePhoto) => void;
}

function formatDate(iso: string) {
  const d = new Date(`${iso}T12:00:00`);
  return d.toLocaleDateString(undefined, {
    weekday: 'long',
    year: 'numeric',
    month: 'long',
    day: 'numeric',
  });
}

function formatTime(at: number) {
  return new Date(at).toLocaleString(undefined, {
    month: 'short',
    day: 'numeric',
    hour: 'numeric',
    minute: '2-digit',
  });
}

const TABS: { id: Tab; label: string }[] = [
  { id: 'overview', label: 'Overview' },
  { id: 'volunteers', label: 'Volunteers' },
  { id: 'reports', label: 'Reports' },
  { id: 'photos', label: 'Photos' },
  { id: 'history', label: 'History' },
];

export default function SiteDetail({
  site,
  regionName,
  onClose,
  onEdit,
  onDelete,
  onStatusChange,
  onAddAssignment,
  onRemoveAssignment,
  onAddReport,
  onDeleteReport,
  onPhotoUpload,
  onDeletePhoto,
  onPhotoClick,
}: SiteDetailProps) {
  const [tab, setTab] = useState<Tab>('overview');
  const joined = volunteersJoined(site);
  const pct = Math.min(100, Math.round((joined / Math.max(1, site.volunteersNeeded)) * 100));
  const spotsLeft = Math.max(0, site.volunteersNeeded - joined);
  const totalBags = site.reports.reduce((sum, r) => sum + (r.bagsCollected ?? 0), 0);

  const tabLabel = (id: Tab, label: string) => {
    if (id === 'volunteers') return `${label} (${joined})`;
    if (id === 'reports') return `${label} (${site.reports.length})`;
    if (id === 'photos') return `${label} (${site.photos.length})`;
    return label;
  };

  return (
    <div className="detail-panel">
      <div className="detail-header">
        <span className={`badge badge-${site.status}`}>{STATUS_LABELS[site.status]}</span>
        <button className="icon-button" onClick={onClose} aria-label="Close details">
          ✕
        </button>
      </div>

      <h2>{site.name}</h2>
      <p className="detail-organizer">
        Organized by {site.organizer}
        {regionName && ` · ${regionName}`}
      </p>

      <nav className="tab-bar">
        {TABS.map((t) => (
          <button
            key={t.id}
            className={`tab ${tab === t.id ? 'active' : ''}`}
            onClick={() => setTab(t.id)}
          >
            {tabLabel(t.id, t.label)}
          </button>
        ))}
      </nav>

      {tab === 'overview' && (
        <OverviewTab
          site={site}
          pct={pct}
          joined={joined}
          spotsLeft={spotsLeft}
          totalBags={totalBags}
          onEdit={onEdit}
          onDelete={onDelete}
          onStatusChange={onStatusChange}
        />
      )}
      {tab === 'volunteers' && (
        <VolunteersTab
          site={site}
          joined={joined}
          spotsLeft={spotsLeft}
          onAdd={onAddAssignment}
          onRemove={onRemoveAssignment}
        />
      )}
      {tab === 'reports' && (
        <ReportsTab site={site} onAdd={onAddReport} onDelete={onDeleteReport} />
      )}
      {tab === 'photos' && (
        <PhotosTab
          site={site}
          onUpload={onPhotoUpload}
          onDelete={onDeletePhoto}
          onPhotoClick={onPhotoClick}
        />
      )}
      {tab === 'history' && <HistoryTab site={site} />}
    </div>
  );
}

/* ---------- Overview ---------- */

function OverviewTab({
  site,
  pct,
  joined,
  spotsLeft,
  totalBags,
  onEdit,
  onDelete,
  onStatusChange,
}: {
  site: CleanupSite;
  pct: number;
  joined: number;
  spotsLeft: number;
  totalBags: number;
  onEdit: (site: CleanupSite) => void;
  onDelete: (id: string) => void;
  onStatusChange: (id: string, status: SiteStatus, note?: string) => void;
}) {
  const [statusNote, setStatusNote] = useState('');
  const [pendingStatus, setPendingStatus] = useState<SiteStatus>(site.status);

  return (
    <div className="tab-body">
      <p className="detail-date">📅 {formatDate(site.date)}</p>
      <p className="detail-description">{site.description}</p>

      <div className="tag-row">
        {site.wasteTypes.map((w) => (
          <span key={w} className="tag">
            {w}
          </span>
        ))}
      </div>

      <div className="detail-volunteers">
        <div className="volunteer-bar large">
          <div className="volunteer-fill" style={{ width: `${pct}%` }} />
        </div>
        <p>
          <strong>{joined}</strong> of <strong>{site.volunteersNeeded}</strong> volunteers
          joined
          {spotsLeft > 0 ? ` — ${spotsLeft} spots left` : ' — fully staffed! 🎉'}
        </p>
        {totalBags > 0 && <p>🗑️ {totalBags} bags collected so far</p>}
      </div>

      <div className="detail-actions">
        <label className="status-select-label">
          Status
          <select
            value={pendingStatus}
            onChange={(e) => setPendingStatus(e.target.value as SiteStatus)}
          >
            {(Object.keys(STATUS_LABELS) as SiteStatus[]).map((s) => (
              <option key={s} value={s}>
                {STATUS_LABELS[s]}
              </option>
            ))}
          </select>
        </label>
        <button
          className="secondary-button"
          disabled={pendingStatus === site.status}
          onClick={() => {
            onStatusChange(site.id, pendingStatus, statusNote);
            setStatusNote('');
          }}
        >
          Apply
        </button>
      </div>
      {pendingStatus !== site.status && (
        <input
          className="status-note-input"
          value={statusNote}
          onChange={(e) => setStatusNote(e.target.value)}
          placeholder="Note for the history log (optional)"
        />
      )}

      <div className="detail-actions">
        <button className="secondary-button" onClick={() => onEdit(site)}>
          Edit
        </button>
        <button
          className="danger-button"
          onClick={() => {
            if (window.confirm(`Remove "${site.name}" from the map?`)) {
              onDelete(site.id);
            }
          }}
        >
          Delete
        </button>
      </div>

      <p className="detail-coords">
        {site.lat.toFixed(5)}, {site.lng.toFixed(5)}
      </p>
    </div>
  );
}

/* ---------- Volunteers ---------- */

function VolunteersTab({
  site,
  joined,
  spotsLeft,
  onAdd,
  onRemove,
}: {
  site: CleanupSite;
  joined: number;
  spotsLeft: number;
  onAdd: (siteId: string, a: { name: string; role: string }) => void;
  onRemove: (siteId: string, assignmentId: string) => void;
}) {
  const [name, setName] = useState('');
  const [role, setRole] = useState<string>(VOLUNTEER_ROLES[0]);

  const submit = () => {
    if (!name.trim()) return;
    onAdd(site.id, { name: name.trim(), role });
    setName('');
  };

  return (
    <div className="tab-body">
      <p className="tab-summary">
        {joined} joined · {spotsLeft > 0 ? `${spotsLeft} spots left` : 'fully staffed'}
      </p>
      <ul className="volunteer-list">
        {site.assignments.map((a) => (
          <li key={a.id}>
            <div className="volunteer-info">
              <strong>{a.name}</strong>
              <span className="role-badge">{a.role}</span>
            </div>
            <div className="volunteer-side">
              <span className="volunteer-since">{formatTime(a.assignedAt)}</span>
              <button
                className="manage-delete"
                onClick={() => onRemove(site.id, a.id)}
                aria-label={`Remove ${a.name}`}
              >
                ✕
              </button>
            </div>
          </li>
        ))}
        {site.assignments.length === 0 && (
          <li className="tab-empty">No volunteers yet — be the first!</li>
        )}
      </ul>
      {site.status !== 'completed' && (
        <div className="inline-form">
          <input
            value={name}
            onChange={(e) => setName(e.target.value)}
            placeholder="Volunteer name"
            onKeyDown={(e) => e.key === 'Enter' && submit()}
          />
          <select value={role} onChange={(e) => setRole(e.target.value)}>
            {VOLUNTEER_ROLES.map((r) => (
              <option key={r} value={r}>
                {r}
              </option>
            ))}
          </select>
          <button className="primary-button compact" onClick={submit}>
            Assign
          </button>
        </div>
      )}
    </div>
  );
}

/* ---------- Reports ---------- */

function ReportsTab({
  site,
  onAdd,
  onDelete,
}: {
  site: CleanupSite;
  onAdd: (
    siteId: string,
    r: { author: string; text: string; bagsCollected?: number },
  ) => void;
  onDelete: (siteId: string, reportId: string) => void;
}) {
  const [author, setAuthor] = useState('');
  const [text, setText] = useState('');
  const [bags, setBags] = useState('');

  const submit = () => {
    if (!text.trim()) return;
    const bagsNum = bags.trim() === '' ? undefined : Math.max(0, Math.round(Number(bags)));
    onAdd(site.id, { author, text, bagsCollected: bagsNum });
    setText('');
    setBags('');
  };

  return (
    <div className="tab-body">
      <ul className="report-list">
        {site.reports.map((r) => (
          <li key={r.id} className="report-card">
            <div className="report-head">
              <strong>{r.author}</strong>
              <span>{formatTime(r.at)}</span>
              <button
                className="manage-delete"
                onClick={() => onDelete(site.id, r.id)}
                aria-label="Delete report"
              >
                ✕
              </button>
            </div>
            <p>{r.text}</p>
            {r.bagsCollected !== undefined && (
              <span className="bags-badge">🗑️ {r.bagsCollected} bags</span>
            )}
          </li>
        ))}
        {site.reports.length === 0 && (
          <li className="tab-empty">No field reports yet.</li>
        )}
      </ul>
      <div className="inline-form column">
        <input
          value={author}
          onChange={(e) => setAuthor(e.target.value)}
          placeholder="Your name"
        />
        <textarea
          value={text}
          onChange={(e) => setText(e.target.value)}
          rows={2}
          placeholder="Progress update, issue, or observation…"
        />
        <div className="inline-form">
          <input
            type="number"
            min={0}
            value={bags}
            onChange={(e) => setBags(e.target.value)}
            placeholder="Bags (optional)"
          />
          <button className="primary-button compact" onClick={submit}>
            Post report
          </button>
        </div>
      </div>
    </div>
  );
}

/* ---------- Photos ---------- */

function PhotosTab({
