{"cmd":"cat > /workspace/cleanup-tracker/src/App.tsx << 'TSXEOF'
import { useMemo, useState } from 'react';
import 'leaflet/dist/leaflet.css';
import CleanupMap, { type PlacementMode } from './components/CleanupMap';
import Sidebar, { type Filters } from './components/Sidebar';
import SiteDetail from './components/SiteDetail';
import SiteForm, { type SiteFormValues } from './components/SiteForm';
import RegionForm, { type RegionFormValues } from './components/RegionForm';
import PinForm, { type PinFormValues } from './components/PinForm';
import PhotoLightbox from './components/PhotoLightbox';
import { useCleanupSites } from './hooks/useCleanupSites';
import { distanceMeters } from './utils/geo';
import { fileToDataUrl } from './utils/image';
import type { CleanupSite, Region, SitePhoto } from './types';
import './app.css';

type FormState =
  | { kind: 'site'; editing: CleanupSite | null }
  | { kind: 'region' }
  | { kind: 'pin' }
  | null;

function regionForPoint(
  regions: Region[],
  point: { lat: number; lng: number },
): string | null {
  let best: { id: string; distance: number } | null = null;
  for (const region of regions) {
    const d = distanceMeters(point, region.center);
    if (d <= region.radiusMeters && (!best || d < best.distance)) {
      best = { id: region.id, distance: d };
    }
  }
  return best?.id ?? null;
}

export default function App() {
  const {
    sites,
    regions,
    pins,
    addSite,
    updateSite,
    deleteSite,
    setSiteStatus,
    addAssignment,
    removeAssignment,
    addReport,
    deleteReport,
    addPhoto,
    deletePhoto,
    addRegion,
    deleteRegion,
    addPin,
    deletePin,
  } = useCleanupSites();

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [placementMode, setPlacementMode] = useState<PlacementMode>(null);
  const [draftPin, setDraftPin] = useState<{ lat: number; lng: number } | null>(null);
  const [form, setForm] = useState<FormState>(null);
  const [lightboxPhoto, setLightboxPhoto] = useState<SitePhoto | null>(null);
  const [flyTo, setFlyTo] = useState<{ lat: number; lng: number; zoom?: number } | null>(null);
  const [filters, setFilters] = useState<Filters>({
    statuses: new Set(),
    wasteTypes: new Set(),
    regionId: null,
    search: '',
  });

  const filteredSites = useMemo(() => {
    const q = filters.search.trim().toLowerCase();
    return sites.filter((site) => {
      if (filters.regionId && site.regionId !== filters.regionId) return false;
      if (filters.statuses.size > 0 && !filters.statuses.has(site.status)) return false;
      if (
        filters.wasteTypes.size > 0 &&
        !site.wasteTypes.some((w) => filters.wasteTypes.has(w))
      )
        return false;
      if (
        q &&
        !site.name.toLowerCase().includes(q) &&
        !site.organizer.toLowerCase().includes(q) &&
        !site.description.toLowerCase().includes(q)
      )
        return false;
      return true;
    });
  }, [sites, filters]);

  const selectedSite = sites.find((s) => s.id === selectedId) ?? null;
  const selectedRegionName = selectedSite?.regionId
    ? (regions.find((r) => r.id === selectedSite.regionId)?.name ?? null)
    : null;

  const handleSelect = (id: string) => {
    setSelectedId(id);
    const site = sites.find((s) => s.id === id);
    if (site) setFlyTo({ lat: site.lat, lng: site.lng });
  };

  const handleMapClick = (lat: number, lng: number) => {
    if (!placementMode) return;
    setDraftPin({ lat, lng });
    if (placementMode === 'site') setForm({ kind: 'site', editing: null });
    if (placementMode === 'region') setForm({ kind: 'region' });
    if (placementMode === 'pin') setForm({ kind: 'pin' });
  };

  const closeForm = () => {
    setForm(null);
    setDraftPin(null);
    setPlacementMode(null);
  };

  const handleSiteSubmit = (values: SiteFormValues) => {
    const regionId = values.regionId ?? regionForPoint(regions, values);
    if (form?.kind === 'site' && form.editing) {
      updateSite(form.editing.id, { ...values, regionId });
      setSelectedId(form.editing.id);
    } else {
      const created = addSite({
        ...values,
        regionId,
        assignments: [],
        reports: [],
        photos: [],
      });
      setSelectedId(created.id);
      setFlyTo({ lat: created.lat, lng: created.lng });
    }
    closeForm();
  };

  const handleRegionSubmit = (values: RegionFormValues) => {
    const created = addRegion(values);
    setFlyTo({ lat: created.center.lat, lng: created.center.lng, zoom: 13 });
    closeForm();
  };

  const handlePinSubmit = (values: PinFormValues) => {
    addPin(values);
    closeForm();
  };

  const handlePhotoUpload = async (siteId: string, file: File, caption: string) => {
    const dataUrl = await fileToDataUrl(file);
    if (dataUrl) addPhoto(siteId, { dataUrl, caption });
  };

  return (
    <div className="app">
      <Sidebar
        sites={filteredSites}
        allSites={sites}
        regions={regions}
        pins={pins}
        filters={filters}
        onFiltersChange={setFilters}
        selectedId={selectedId}
        onSelect={handleSelect}
        placementMode={placementMode}
        onPlacementModeChange={(mode) => {
          setPlacementMode(mode);
          setDraftPin(null);
        }}
        onDeleteRegion={deleteRegion}
        onDeletePin={deletePin}
        onFlyTo={setFlyTo}
      />
      <main className="map-area">
        <CleanupMap
          sites={filteredSites}
          regions={regions}
          pins={pins}
          selectedId={selectedId}
          onSelectSite={handleSelect}
          onDeletePin={deletePin}
          placementMode={placementMode}
          onMapClick={handleMapClick}
          draftPin={draftPin}
          flyTo={flyTo}
        />
        {selectedSite && !form && (
          <SiteDetail
            site={selectedSite}
            regionName={selectedRegionName}
            onClose={() => setSelectedId(null)}
            onEdit={(site) => setForm({ kind: 'site', editing: site })}
            onDelete={(id) => {
              deleteSite(id);
              setSelectedId(null);
            }}
            onStatusChange={setSiteStatus}
            onAddAssignment={addAssignment}
            onRemoveAssignment={removeAssignment}
            onAddReport={addReport}
            onDeleteReport={deleteReport}
            onPhotoUpload={handlePhotoUpload}
            onDeletePhoto={deletePhoto}
            onPhotoClick={setLightboxPhoto}
          />
        )}
      </main>

      {form?.kind === 'site' && (
        <SiteForm
          initial={form.editing ?? undefined}
          regions={regions}
          draftLocation={draftPin}
          onSubmit={handleSiteSubmit}
          onCancel={closeForm}
        />
      )}
      {form?.kind === 'region' && draftPin && (
        <RegionForm center={draftPin} onSubmit={handleRegionSubmit} onCancel={closeForm} />
      )}
      {form?.kind === 'pin' && draftPin && (
        <PinForm location={draftPin} onSubmit={handlePinSubmit} onCancel={closeForm} />
      )}
      {lightboxPhoto && (
        <PhotoLightbox photo={lightboxPhoto} onClose={() => setLightboxPhoto(null)} />
      )}
    </div>
  );
}
TSXEOF"}

