{"cmd":"cat > /workspace/cleanup-tracker/src/utils/duplicate.ts << 'TSEOF'
import type { SiteReport } from '../types';

const DUPLICATE_THRESHOLD = 0.82;
const WARNING_THRESHOLD = 0.55;
const NEAR_IDENTICAL_TOKEN_JACCARD = 0.9;
const AUTHOR_SIMILARITY_BONUS = 0.05;

function normalize(text: string): string {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function trigrams(normalized: string): Set<string> {
  const padded = ` ${normalized} `;
  const grams = new Set<string>();
  for (let i = 0; i + 3 <= padded.length; i++) {
    grams.add(padded.slice(i, i + 3));
  }
  return grams;
}

function jaccard(a: Set<string>, b: Set<string>): number {
  if (a.size === 0 || b.size === 0) return 0;
  let intersection = 0;
  for (const item of a) if (b.has(item)) intersection++;
  return intersection / (a.size + b.size - intersection);
}

/** Hybrid text similarity: 0.7 × trigram Jaccard + 0.3 × token Jaccard. */
export function textSimilarity(a: string, b: string): number {
  const na = normalize(a);
  const nb = normalize(b);
  if (!na || !nb) return 0;
  const tokenA = new Set(na.split(' '));
  const tokenB = new Set(nb.split(' '));
  return 0.7 * jaccard(trigrams(na), trigrams(nb)) + 0.3 * jaccard(tokenA, tokenB);
}

export interface DuplicateMatch {
  report: SiteReport;
  score: number;
}

/**
 * Compare candidate text against existing reports on a site, most similar
 * first. Passing an author applies a small bonus to their own reports so
 * accidental double-posting is caught more aggressively.
 */
export function findDuplicates(
  text: string,
  reports: SiteReport[],
  author?: string,
): DuplicateMatch[] {
  if (normalize(text).length < 12) return [];
  const authorKey = author?.trim().toLowerCase();
  return reports
    .map((report) => {
      let score = textSimilarity(text, report.text);
      if (authorKey && report.author.trim().toLowerCase() === authorKey) {
        score = Math.min(1, score + AUTHOR_SIMILARITY_BONUS);
      }
      return { report, score };
    })
    .filter((m) => m.score >= WARNING_THRESHOLD)
    .sort((a, b) => b.score - a.score);
}

/** Is this match strong enough to auto-flag the incoming report as a duplicate? */
export function isAutoFlag(match: DuplicateMatch, author?: string): boolean {
  if (match.score >= DUPLICATE_THRESHOLD) return true;
  const sameAuthor =
    !!author?.trim() &&
    author.trim().toLowerCase() === match.report.author.trim().toLowerCase();
  const tokenA = new Set(normalize(match.report.text).split(' '));
  const tokenB = new Set(normalize(match.report.text).split(' '));
  return (
    sameAuthor &&
    match.score >= WARNING_THRESHOLD &&
    jaccard(tokenA, tokenB) >= NEAR_IDENTICAL_TOKEN_JACCARD
  );
}
TSEOF"}

