  });
}

/** Cluster badge colored by its dominant site status. */
function makeSiteClusterIcon(cluster: L.MarkerCluster) {
  const counts: Record<SiteStatus, number> = { planned: 0, active: 0, completed: 0 };
  for (const marker of cluster.getAllChildMarkers()) {
    const status = (marker.options as { siteStatus?: SiteStatus }).siteStatus;
    if (status) counts[status]++;
  }
  const dominant = (Object.entries(counts) as [SiteStatus, number][]).sort(
    (a, b) => b[1] - a[1],
  )[0][0];
  const total = cluster.getChildCount();
  const size = total < 10 ? 34 : total < 100 ? 40 : 46;
  return L.divIcon({
