    iconSize: [size, size],
    html: `<div class="cluster-badge cluster-${dominant}" style="width:${size}px;height:${size}px"><span>${total}</span></div>`,
  });
}

function makePinClusterIcon(cluster: L.MarkerCluster) {
  const total = cluster.getChildCount();
  const size = total < 10 ? 30 : total < 100 ? 36 : 42;
