function ClickHandler({
  placementMode,
  onMapClick,
}: {
  placementMode: PlacementMode;
  onMapClick: (lat: number, lng: number) => void;
}) {
  useMapEvents({
    click(e) {
      if (placementMode) onMapClick(e.latlng.lat, e.latlng.lng);
    },
  });
  return null;
}

function CursorStyle({ placementMode }: { placementMode: PlacementMode }) {
  const map = useMap();
  useEffect(() => {
    const el = map.getContainer();
    el.style.cursor = placementMode ? 'crosshair' : '';
    return () => {
      el.style.cursor = '';
    };
  }, [map, placementMode]);
  return null;
}

/** Tracks the live viewport so only in-bounds markers get mounted. */
function ViewportTracker({ onChange }: { onChange: (bounds: L.LatLngBounds) => void }) {
  const map = useMap();
  useEffect(() => {
    const update = () => onChange(map.getBounds().pad(0.25));
    update();
    map.on('moveend zoomend', update);
    return () => {
      map.off('moveend zoomend', update);
    };
  }, [map, onChange]);
  return null;
}

function FlyTo({ target }: { target: { lat: number; lng: number; zoom?: number } | null }) {
  const map = useMap();
  useEffect(() => {
    if (target) {
      map.flyTo([target.lat, target.lng], target.zoom ?? 15, { duration: 0.8 });
    }
  }, [target, map]);
  return null;
}

/** Custom control that zooms the map to fit all currently visible sites. */
function FitToSitesControl({ sites }: { sites: CleanupSite[] }) {
  const map = useMap();
  useEffect(() => {
    const control = new L.Control({ position: 'topleft' });
    control.onAdd = () => {
      const btn = L.DomUtil.create('button', 'fit-sites-control');
      btn.type = 'button';
      btn.title = 'Zoom to fit visible sites';
      btn.textContent = '⤢';
      L.DomEvent.disableClickPropagation(btn);
      L.DomEvent.on(btn, 'click', () => {
        if (sites.length === 0) return;
        const bounds = L.latLngBounds(sites.map((s) => [s.lat, s.lng] as [number, number]));
        map.flyToBounds(bounds.pad(0.15), { duration: 0.6, maxZoom: 15 });
      });
      return btn;
    };
    map.addControl(control);
    return () => {
      map.removeControl(control);
    };
  }, [map, sites]);
  return null;
}

